-- Risk Management Database Backup
-- Date: 2026-07-11 06:36:15

SET FOREIGN_KEY_CHECKS=0;

DROP TABLE IF EXISTS `login_attempts`;
CREATE TABLE `login_attempts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `ip_address` varchar(45) COLLATE utf8mb4_unicode_ci NOT NULL,
  `attempt_time` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_username` (`username`),
  KEY `idx_ip_address` (`ip_address`),
  KEY `idx_attempt_time` (`attempt_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `password_resets`;
CREATE TABLE `password_resets` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `token` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `expires_at` datetime NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_token` (`token`),
  CONSTRAINT `password_resets_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `risk_reports`;
CREATE TABLE `risk_reports` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `risk_id` int(11) NOT NULL,
  `corrective_action` text COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'มาตรการแก้ไข',
  `responsible_person` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'ผู้รับผิดชอบ',
  `follow_up` text COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'การติดตามผล',
  `expected_outcome` text COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'ผลที่คาดว่าจะได้รับ',
  `report_file` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'ไฟล์แนบ',
  `created_by` int(11) NOT NULL COMMENT 'ผู้สร้างรายงาน',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_risk_id` (`risk_id`),
  KEY `idx_created_by` (`created_by`),
  CONSTRAINT `risk_reports_ibfk_1` FOREIGN KEY (`risk_id`) REFERENCES `risks` (`id`) ON DELETE CASCADE,
  CONSTRAINT `risk_reports_ibfk_2` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `risk_reports` (`id`, `risk_id`, `corrective_action`, `responsible_person`, `follow_up`, `expected_outcome`, `report_file`, `created_by`, `created_at`, `updated_at`) VALUES
('1', '11', 'ประชุมคณะทำงานเพื่อปรับแผนการใช้จ่ายใหม่ จัดลำดับความสำคัญกิจกรรมที่จำเป็นเร่งด่วนก่อน', 'นายสมชาย ใจดี', 'รอการอนุมัติแผนการใช้จ่ายใหม่จากคณะกรรมการ', 'สามารถดำเนินกิจกรรมสำคัญได้ 70% ภายในปีงบประมาณ', NULL, '3', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('2', '12', 'เร่งรัดทุกกลุ่มงานให้เบิกจ่ายตามแผนที่กำหนด จัดทำปฏิทินเร่งรัดการเบิกจ่ายรายสัปดาห์', 'นางวิไล พัฒนา', 'เบิกจ่ายเพิ่มขึ้นจาก 60% เป็น 85% ภายใน 1 เดือน', 'เบิกจ่ายได้ตามเป้าหมาย 95% ภายในสิ้นไตรมาส', NULL, '1', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('3', '13', 'ส่งเรื่องคืนพัสดุและขอเปลี่ยนเป็นรุ่นที่ถูกต้องตามสเปค ดำเนินการตามระเบียบพัสดุ', 'นายประเสริฐ มั่นคง', 'ได้รับพัสดุใหม่ที่ถูกต้องตามสเปคภายใน 2 สัปดาห์', 'การจัดซื้อจัดจ้างเป็นไปตามระเบียบ 100%', NULL, '4', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('4', '16', 'จัดทำนโยบาย PDPA อบรมบุคลากร 200 คน และจัดทำระบบขอความยินยอมออนไลน์', 'นายประเสริฐ มั่นคง', 'ผ่านการตรวจสอบจาก สคส. เรียบร้อย ไม่พบการละเมิดข้อมูล', 'หน่วยงานปฏิบัติตาม PDPA ได้ 100% ภายใน 6 เดือน', NULL, '1', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('5', '17', 'อบรมระเบียบพัสดุจัดซื้อจัดจ้าง จัดทำคู่มือการจัดซื้อที่ถูกต้อง และมีระบบตรวจสอบภายใน', 'นายประเสริฐ มั่นคง', 'ผ่านการตรวจสอบจาก สตง. ไม่พบข้อทักท้วงในรอบปี', 'การจัดซื้อจัดจ้างถูกต้องตามระเบียบ 100%', NULL, '4', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('6', '22', 'ซ่อมแซมเครื่องปรับอากาศและจัดทำแผนเปลี่ยนเครื่องปรับอากาศที่อายุเกิน 10 ปี', 'นางสมศรี รักงาน', 'ซ่อมแล้วเสร็จ 3 เครื่อง อยู่ระหว่างของบประมาณเปลี่ยน 5 เครื่อง', 'ระบบปรับอากาศใช้งานได้ 100% ภายใน 2 เดือน', NULL, '3', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('7', '26', 'ปรับปรุงระบบนัดหมายโดยเพิ่มฟังก์ชั่นตัวอักษรใหญ่และเสียงภาษาไทย อบรม อสม. 50 คน', 'นายสมพงษ์ ก้าวหน้า', 'ผู้สูงอายุใช้งานเพิ่มขึ้นจาก 40% เป็น 75% ภายใน 3 เดือน', 'ผู้สูงอายุใช้งานระบบออนไลน์ได้ 80% ภายใน 6 เดือน', NULL, '5', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('8', '8', 'สรรหาเจ้าหน้าที่การเงินใหม่และจัดทำระบบส่งมอบงาน (Turnover Checklist) ที่เป็นมาตรฐาน', 'นายประเสริฐ มั่นคง', 'ได้เจ้าหน้าที่ใหม่ภายใน 2 สัปดาห์ ระบบส่งมอบงานแล้วเสร็จ', 'การส่งมอบงานมีประสิทธิภาพ ลดความเสี่ยงการหยุดชะงัก', NULL, '4', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('9', '23', 'ปิดพื้นที่สนามเด็กเล่นและฟื้นฟูสภาพแวดล้อม เก็บตัวอย่างตรวจซ้ำ 5 จุด', 'นายสมชาย ใจดี', 'ผลตรวจซ้ำอยู่ในเกณฑ์ปลอดภัย เปิดใช้สนามเด็กเล่นได้ตามปกติ', 'สารตะกั่วในดินไม่เกินมาตรฐาน ภายใน 2 เดือน', NULL, '1', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('10', '25', 'ติดตั้งเครื่องสำรองไฟฉุกเฉิน (Generator) ขนาด 500 kVA และบำรุงรักษาหม้อแปลงไฟฟ้า', 'นางสมศรี รักงาน', 'ติดตั้งแล้วเสร็จ ทดสอบระบบทำงานได้ตามมาตรฐาน', 'ไฟฟ้าสำรองพร้อมใช้งานภายใน 30 วินาที เมื่อไฟฟ้าดับ', NULL, '4', '2026-07-11 11:15:48', '2026-07-11 11:15:48');

DROP TABLE IF EXISTS `risks`;
CREATE TABLE `risks` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `reporter_code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'รหัสผู้รายงาน',
  `unit` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'กลุ่มงาน/หน่วยงาน',
  `unit_other` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'หน่วยงานอื่นๆ (กรณีเลือกอื่นๆ)',
  `risk_type` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ประเภทความเสี่ยง',
  `risk_type_other` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'ประเภทความเสี่ยงอื่นๆ',
  `severity` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ระดับความรุนแรง (A-F)',
  `severity_other` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'ระดับความรุนแรงอื่นๆ',
  `event_datetime` datetime NOT NULL COMMENT 'วันที่เกิดเหตุการณ์',
  `report_datetime` datetime NOT NULL COMMENT 'วันที่รายงาน',
  `detail` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'รายละเอียดเหตุการณ์',
  `initial_solution` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'แนวทางแก้ไขเบื้องต้น',
  `suggestion` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ข้อเสนอแนะ',
  `status` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT 'ยังไม่ดำเนินการ' COMMENT 'สถานะการดำเนินการ',
  `consent` tinyint(1) DEFAULT 0 COMMENT '0=ยังไม่ยินยอม, 1=ยินยอมแล้ว',
  `consent_at` datetime DEFAULT NULL COMMENT 'วันที่ให้ความยินยอม',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_status` (`status`),
  KEY `idx_risk_type` (`risk_type`),
  KEY `idx_severity` (`severity`),
  KEY `idx_unit` (`unit`),
  CONSTRAINT `risks_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `risks` (`id`, `user_id`, `reporter_code`, `unit`, `unit_other`, `risk_type`, `risk_type_other`, `severity`, `severity_other`, `event_datetime`, `report_datetime`, `detail`, `initial_solution`, `suggestion`, `status`, `consent`, `consent_at`, `created_at`, `updated_at`) VALUES
('1', '2', 'R10002', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยทำงาน', NULL, 'ความเสี่ยงทางด้านกลยุทธ์', NULL, 'E', NULL, '2026-06-01 09:00:00', '2026-06-01 14:00:00', 'แผนยุทธศาสตร์การพัฒนาสุขภาพวัยทำงาน 5 ปี ไม่สอดคล้องกับนโยบายกระทรวงสาธารณสุขที่ปรับเปลี่ยนใหม่ ทำให้ไม่สามารถขออนุมัติงบประมาณได้', 'ประชุมคณะกรรมการทบทวนแผนยุทธศาสตร์เร่งด่วน และปรับแผนให้สอดคล้องกับนโยบายใหม่ภายใน 2 สัปดาห์', 'ควรมีระบบติดตามและวิเคราะห์นโยบายกระทรวงแบบ Real-time และปรับแผนยุทธศาสตร์ทุก 6 เดือน', 'ยุติ', '1', '2026-06-01 15:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('2', '3', 'R10003', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยเรียน', NULL, 'ความเสี่ยงทางด้านกลยุทธ์', NULL, 'D', NULL, '2026-06-10 10:00:00', '2026-06-10 11:30:00', 'โครงการส่งเสริมสุขภาพวัยเรียนปี 2569 ไม่ได้รับการจัดสรรงบประมาณ เนื่องจากแผนงานไม่ชัดเจนและขาดตัวชี้วัดที่เป็นรูปธรรม', 'ปรับแผนโครงการใหม่โดยเพิ่ม KPI ที่วัดผลได้ชัดเจน และเสนอขออนุมัติงบประมาณรอบพิเศษ', 'ควรจัดทำแผนงานล่วงหน้า 1 ปีพร้อมตัวชี้วัดที่ชัดเจน และนำเสนอคณะกรรมการพิจารณางบประมาณก่อนกำหนด', 'กำลังดำเนินการ', '1', '2026-06-10 13:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('3', '4', 'R10004', 'กลุ่มขับเคลื่อนยุทธศาสตร์และพัฒนากำลังคน', NULL, 'ความเสี่ยงทางด้านกลยุทธ์', NULL, 'A', NULL, '2026-06-30 08:00:00', '2026-06-30 09:00:00', 'ผลการประเมินความพึงพอใจของบุคลากรต่อแผนพัฒนากำลังคนต่ำกว่าเกณฑ์ที่กำหนด (60%) เนื่องจากขาดการมีส่วนร่วมในการจัดทำแผน', 'จัดประชุม Focus Group รับฟังความคิดเห็นบุคลากรทุกระดับ และปรับแผนพัฒนากำลังคนให้ตรงตามความต้องการ', 'ควรจัดทำแบบสำรวจความต้องการพัฒนาตนเองประจำปี และให้บุคลากรมีส่วนร่วมในการออกแบบหลักสูตรอบรม', 'ดำเนินการแล้ว', '1', '2026-07-01 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('4', '5', 'R10005', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยสูงอายุ', NULL, 'ความเสี่ยงทางด้านกลยุทธ์', NULL, 'C', NULL, '2026-07-05 13:00:00', '2026-07-05 14:30:00', 'แผนพัฒนาระบบดูแลผู้สูงอายุระยะยาว (Long Term Care) ไม่สามารถดำเนินการได้ตามเป้าหมาย เนื่องจากขาดความร่วมมือจากองค์กรปกครองส่วนท้องถิ่น', 'จัดประชุมชี้แจงและสร้างความร่วมมือกับ อบต./เทศบาล 10 แห่ง พร้อมลงนาม MOU ความร่วมมือ', 'ควรจัดทำแผนปฏิบัติการร่วมกับ อปท. ล่วงหน้า และมีระบบติดตามประเมินผลทุกไตรมาส', 'อยู่ระหว่างดำเนินการ', '0', NULL, '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('5', '1', 'R10001', 'กลุ่มอำนวยการ', NULL, 'ความเสี่ยงทางด้านกลยุทธ์', NULL, 'B', NULL, '2026-06-15 10:00:00', '2026-06-15 11:00:00', 'การถ่ายทอดตัวชี้วัดจากระดับกรมลงสู่ระดับศูนย์ไม่ชัดเจน ทำให้เกิดความสับสนในการรายงานผล', 'จัดประชุมชี้แจงตัวชี้วัดกับทุกกลุ่มงาน และจัดทำคู่มือการรายงานผลที่เป็นมาตรฐานเดียวกัน', 'ควรมีระบบการสื่อสารตัวชี้วัดแบบ Cascade จากบนลงล่าง พร้อมปฏิทินการรายงานที่ชัดเจน', 'ดำเนินการแล้ว', '1', '2026-06-16 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('6', '6', 'R10006', 'กลุ่มพัฒนาอนามัยและสิ่งแวดล้อม', NULL, 'ความเสี่ยงทางด้านการปฏิบัติงาน', NULL, 'D', NULL, '2026-05-10 08:30:00', '2026-05-10 10:00:00', 'เจ้าหน้าที่ขาดทักษะการใช้โปรแกรมวิเคราะห์ข้อมูลสุขภาพ SPSS ทำให้การวิเคราะห์ข้อมูลคลาดเคลื่อนและรายงานผิดพลาด', 'ส่งเจ้าหน้าที่อบรมการใช้ SPSS แบบเร่งด่วน 5 วัน และจัดให้มีพี่เลี้ยงดูแล', 'จัดอบรมการใช้โปรแกรมวิเคราะห์ข้อมูลเป็นประจำทุกปี และมีระบบตรวจสอบคุณภาพข้อมูลก่อนออกรายงาน', 'ดำเนินการแล้ว', '1', '2026-05-11 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('7', '4', 'R10004', 'กลุ่มขับเคลื่อนยุทธศาสตร์และพัฒนากำลังคน', NULL, 'ความเสี่ยงทางด้านการปฏิบัติงาน', NULL, 'B', NULL, '2026-07-07 09:00:00', '2026-07-07 10:00:00', 'ระบบสารบรรณอิเล็กทรอนิกส์ล่ม ทำให้ไม่สามารถส่งหนังสือราชการได้ทันตามกำหนด กระทบ 3 หน่วยงาน', 'ใช้ระบบ Manual ชั่วคราวและประสานงานทางโทรศัพท์แทน แจ้ง IT ดำเนินการแก้ไขด่วน', 'จัดทำระบบสำรองฉุกเฉินและแผนรองรับเมื่อระบบขัดข้อง (BCP) สำหรับงานสารบรรณ', 'ดำเนินการแล้ว', '1', '2026-07-07 14:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('8', '2', 'R10002', 'กลุ่มอำนวยการ', NULL, 'ความเสี่ยงทางด้านการปฏิบัติงาน', NULL, 'F', NULL, '2026-07-28 11:00:00', '2026-07-28 12:00:00', 'เจ้าหน้าที่การเงินลาออกกะทันหันโดยไม่ส่งมอบงาน ทำให้ไม่สามารถเบิกจ่ายงบประมาณได้ กระทบ 15 โครงการ', 'แต่งตั้งคณะทำงานเฉพาะกิจเข้ามาดำเนินการแทนชั่วคราว และเร่งสรรหาเจ้าหน้าที่ใหม่', 'จัดทำแผนสืบทอดตำแหน่ง (Succession Plan) ทุกตำแหน่งสำคัญ และมีระบบส่งมอบงานที่เป็นมาตรฐาน', 'ดำเนินการแล้ว', '1', '2026-07-28 15:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('9', '5', 'R10005', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยสูงอายุ', NULL, 'ความเสี่ยงทางด้านการปฏิบัติงาน', NULL, 'C', NULL, '2026-06-20 09:30:00', '2026-06-20 10:30:00', 'การลงพื้นที่เยี่ยมบ้านผู้สูงอายุติดเตียงไม่เป็นไปตามแผน เนื่องจากพาหนะไม่เพียงพอและเส้นทางบางพื้นที่เข้าถึงยาก', 'ปรับตารางการลงพื้นที่ใหม่โดยจัดกลุ่มตามเส้นทาง และขอความร่วมมือจาก อสม. ในพื้นที่ช่วยสนับสนุน', 'จัดหาพาหนะเพิ่มเติม 2 คันสำหรับงานชุมชน และทำแผนที่เส้นทางการลงพื้นที่อย่างเป็นระบบ', 'อยู่ระหว่างดำเนินการ', '1', '2026-06-21 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('10', '3', 'R10003', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยเรียน', NULL, 'ความเสี่ยงทางด้านการปฏิบัติงาน', NULL, 'A', NULL, '2026-06-15 14:00:00', '2026-06-15 15:00:00', 'อุปกรณ์ตรวจสุขภาพนักเรียน (เครื่องวัดสายตา, เครื่องชั่งน้ำหนัก) ชำรุด 3 เครื่อง ทำให้ตรวจคัดกรองล่าช้า', 'ยืมอุปกรณ์จากกลุ่มงานอื่นชั่วคราว และส่งเครื่องที่ชำรุดเข้าซ่อมด่วน', 'จัดทำแผนบำรุงรักษาเชิงป้องกัน (PM) ทุก 6 เดือน และจัดหาอุปกรณ์สำรองอย่างน้อย 1 ชุด', 'ดำเนินการแล้ว', '1', '2026-06-16 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('11', '3', 'R10003', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยทำงาน', NULL, 'ความเสี่ยงทางด้านการเงิน', NULL, 'D', NULL, '2026-07-07 08:00:00', '2026-07-07 09:00:00', 'งบประมาณโครงการส่งเสริมสุขภาพวัยทำงานถูกตัดลด 30% จากงบกลางปี ทำให้กิจกรรมที่วางแผนไว้ 5 กิจกรรมไม่สามารถดำเนินการได้', 'ประชุมคณะทำงานเพื่อปรับแผนการใช้จ่ายใหม่ จัดลำดับความสำคัญกิจกรรมที่จำเป็นเร่งด่วนก่อน', 'ควรมีการบริหารความเสี่ยงด้านงบประมาณโดยจัดทำแผนสำรองและหาแหล่งทุนสนับสนุนภายนอก', 'ยังไม่ดำเนินการ', '0', NULL, '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('12', '1', 'R10001', 'กลุ่มอำนวยการ', NULL, 'ความเสี่ยงทางด้านการเงิน', NULL, 'E', NULL, '2026-05-25 10:00:00', '2026-05-25 11:00:00', 'การเบิกจ่ายงบประมาณไตรมาส 2 ต่ำกว่าเป้าหมาย 40% เสี่ยงถูกตัดงบประมาณไตรมาส 3-4', 'เร่งรัดทุกกลุ่มงานให้เบิกจ่ายตามแผนที่กำหนด จัดทำปฏิทินเร่งรัดการเบิกจ่ายรายสัปดาห์', 'จัดอบรมระเบียบพัสดุและการเงินแก่ผู้ปฏิบัติงาน และมีระบบติดตามการเบิกจ่ายแบบ Real-time', 'ดำเนินการแล้ว', '1', '2026-05-26 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('13', '4', 'R10004', 'กลุ่มขับเคลื่อนยุทธศาสตร์และพัฒนากำลังคน', NULL, 'ความเสี่ยงทางด้านการเงิน', NULL, 'C', NULL, '2026-06-25 15:00:00', '2026-06-25 16:00:00', 'พัสดุครุภัณฑ์ที่จัดซื้อมาไม่ตรงตามสเปคที่กำหนด (Specification) ทำให้สูญเสียงบประมาณ 150,000 บาท', 'ส่งเรื่องคืนพัสดุและขอเปลี่ยนเป็นรุ่นที่ถูกต้องตามสเปค ดำเนินการตามระเบียบพัสดุ', 'แต่งตั้งคณะกรรมการตรวจรับพัสดุที่มีความเชี่ยวชาญเฉพาะ และตรวจสอบสเปคให้ละเอียดก่อนลงนาม', 'ดำเนินการแล้ว', '1', '2026-06-26 08:30:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('14', '2', 'R10002', 'กลุ่มพัฒนาอนามัยและสิ่งแวดล้อม', NULL, 'ความเสี่ยงทางด้านการเงิน', NULL, 'B', NULL, '2026-06-10 11:00:00', '2026-06-10 12:00:00', 'ค่าใช้จ่ายในการเดินทางไปราชการเกินวงเงินที่กำหนด เนื่องจากราคาน้ำมันและที่พักปรับตัวสูงขึ้น', 'ขออนุมัติขยายวงเงินค่าใช้จ่ายในการเดินทางชั่วคราว และปรับแผนการเดินทางให้ใช้พื้นที่ใกล้เคียงก่อน', 'ควรปรับปรุงระเบียบการเบิกจ่ายให้สอดคล้องกับสถานการณ์ปัจจุบัน และใช้ระบบ Video Conference ทดแทนการเดินทาง', 'ดำเนินการแล้ว', '1', '2026-06-11 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('15', '4', 'R10004', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยเรียน', NULL, 'ความเสี่ยงทางด้านการเงิน', NULL, 'A', NULL, '2026-07-01 09:00:00', '2026-07-01 10:00:00', 'ใบเสร็จรับเงินค่าใช้จ่ายในการจัดอบรมสูญหาย 1 ฉบับ มูลค่า 5,000 บาท ทำให้เบิกจ่ายไม่ได้', 'จัดทำใบแทนใบเสร็จรับเงินตามระเบียบราชการ และให้ผู้เกี่ยวข้องลงนามรับรอง', 'ควรใช้ระบบ e-Receipt และจัดเก็บเอกสารการเงินในระบบ Digital ป้องกันการสูญหาย', 'ดำเนินการแล้ว', '1', '2026-07-02 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('16', '1', 'R10001', 'กลุ่มพัฒนาอนามัยและสิ่งแวดล้อม', NULL, 'ความเสี่ยงทางด้านกฎหมาย', NULL, 'E', NULL, '2026-07-07 08:30:00', '2026-07-07 09:30:00', 'ไม่ปฏิบัติตาม พ.ร.บ. คุ้มครองข้อมูลส่วนบุคคล พ.ศ. 2562 (PDPA) เนื่องจากไม่มีระบบจัดเก็บและทำลายข้อมูลผู้รับบริการ', 'แต่งตั้ง DPO (Data Protection Officer) และจัดทำนโยบาย PDPA ของหน่วยงาน พร้อมอบรมบุคลากร', 'จัดทำระบบสารสนเทศที่รองรับ PDPA อย่างสมบูรณ์และตรวจสอบ Compliance ทุก 6 เดือน', 'ยุติ', '1', '2026-07-07 14:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('17', '4', 'R10004', 'กลุ่มขับเคลื่อนยุทธศาสตร์และพัฒนากำลังคน', NULL, 'ความเสี่ยงทางด้านกฎหมาย', NULL, 'D', NULL, '2026-06-05 10:00:00', '2026-06-05 11:00:00', 'การจัดซื้อจัดจ้างไม่เป็นไปตาม พ.ร.บ. จัดซื้อจัดจ้างฯ เนื่องจากแบ่งซื้อของเพื่อหลีกเลี่ยงการจัดซื้อด้วยวิธี e-Bidding', 'ยกเลิกการจัดซื้อครั้งนี้และดำเนินการใหม่ให้ถูกต้องตามระเบียบ สอบสวนผู้เกี่ยวข้อง', 'อบรมระเบียบจัดซื้อจัดจ้างแก่ผู้ปฏิบัติงานทุกคน และมีระบบตรวจสอบภายในที่เข้มแข็ง', 'ดำเนินการแล้ว', '1', '2026-06-06 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('18', '3', 'R10003', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยทำงาน', NULL, 'ความเสี่ยงทางด้านกฎหมาย', NULL, 'C', NULL, '2026-06-20 14:00:00', '2026-06-20 15:00:00', 'ใบอนุญาตประกอบวิชาชีพของนักกายภาพบำบัดหมดอายุ 2 รายโดยไม่มีการต่ออายุ ทำให้เสี่ยงผิดกฎหมายวิชาชีพ', 'แจ้งให้ผู้เกี่ยวข้องดำเนินการต่ออายุใบอนุญาตทันที และงดปฏิบัติงานชั่วคราวจนกว่าจะต่ออายุแล้วเสร็จ', 'จัดทำระบบติดตามวันหมดอายุใบอนุญาตประกอบวิชาชีพของบุคลากรทุกคน และแจ้งเตือนล่วงหน้า 3 เดือน', 'ดำเนินการแล้ว', '1', '2026-06-21 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('19', '5', 'R10005', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยสูงอายุ', NULL, 'ความเสี่ยงทางด้านกฎหมาย', NULL, 'B', NULL, '2026-07-10 09:00:00', '2026-07-10 10:00:00', 'แบบฟอร์มยินยอมให้ข้อมูลสุขภาพ (Consent Form) ไม่ครอบคลุมตามข้อกำหนด PDPA ฉบับใหม่', 'ปรับปรุงแบบฟอร์ม Consent Form ให้เป็นไปตามกฎหมายใหม่ และให้ผู้รับบริการลงนามใหม่ทุกราย', 'ทบทวนและปรับปรุงแบบฟอร์มกฎหมายทุกฉบับให้เป็นปัจจุบันทุก 6 เดือน', 'กำลังดำเนินการ', '1', '2026-07-11 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('20', '2', 'R10002', 'กลุ่มพัฒนาอนามัยและสิ่งแวดล้อม', NULL, 'ความเสี่ยงทางด้านกฎหมาย', NULL, 'A', NULL, '2026-06-15 13:00:00', '2026-06-15 14:00:00', 'ป้ายประชาสัมพันธ์โครงการไม่เป็นไปตามมาตรฐานที่กำหนดตามระเบียบสำนักนายกรัฐมนตรี', 'แก้ไขป้ายประชาสัมพันธ์ให้ถูกต้องตามระเบียบ และตรวจสอบป้ายอื่นๆ ทั้งหมด', 'จัดทำ Template ป้ายประชาสัมพันธ์ที่ได้มาตรฐานและผ่านการตรวจสอบจากนิติกรก่อนใช้งาน', 'ดำเนินการแล้ว', '1', '2026-06-16 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('21', '4', 'R10004', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยเรียน', NULL, 'ความเสี่ยงด้านสิ่งแวดล้อม', NULL, 'C', NULL, '2026-07-07 10:00:00', '2026-07-07 11:00:00', 'น้ำประปาในโรงเรียนไม่สะอาด มีตะกอนและกลิ่นคลอรีนสูง เสี่ยงกระทบสุขภาพนักเรียน 500 คน', 'ประสานงานการประปาส่วนภูมิภาคตรวจสอบคุณภาพน้ำ และจัดหาน้ำดื่มสะอาดให้นักเรียนชั่วคราว', 'ติดตั้งระบบกรองน้ำในโรงเรียนและตรวจสอบคุณภาพน้ำทุก 3 เดือน', 'ยังไม่ดำเนินการ', '0', NULL, '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('22', '2', 'R10002', 'กลุ่มอำนวยการ', NULL, 'ความเสี่ยงด้านสิ่งแวดล้อม', NULL, 'C', NULL, '2026-06-30 08:00:00', '2026-06-30 09:00:00', 'เครื่องปรับอากาศในห้องประชุมใหญ่เสีย 3 เครื่องจาก 5 เครื่อง ประชุมนาน 4 ชั่วโมง อุณหภูมิห้อง 34°C', 'ย้ายการประชุมไปห้องประชุมเล็ก 2 ห้อง ใช้พัดลมช่วยระบายอากาศ และเรียกช่างซ่อมด่วน', 'จัดทำแผนเปลี่ยนเครื่องปรับอากาศที่อายุเกิน 10 ปี และเพิ่มระบบระบายอากาศสำรอง', 'ดำเนินการแล้ว', '1', '2026-07-01 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('23', '1', 'R10001', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยเรียน', NULL, 'ความเสี่ยงด้านสิ่งแวดล้อม', NULL, 'E', NULL, '2026-07-07 14:00:00', '2026-07-07 15:00:00', 'พบสารตะกั่วปนเปื้อนในสนามเด็กเล่นโรงเรียนอนุบาลในเขตพื้นที่รับผิดชอบ เกินมาตรฐาน 3 เท่า', 'ปิดพื้นที่สนามเด็กเล่นทันที แจ้งผู้บริหารโรงเรียนและหน่วยงานที่เกี่ยวข้อง เก็บตัวอย่างตรวจซ้ำ', 'จัดทำแผนฟื้นฟูสภาพแวดล้อมในโรงเรียนและสุ่มตรวจสารปนเปื้อนในโรงเรียนทุกแห่งในพื้นที่', 'กำลังดำเนินการ', '1', '2026-07-08 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('24', '3', 'R10003', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยทำงาน', NULL, 'ความเสี่ยงด้านสิ่งแวดล้อม', NULL, 'B', NULL, '2026-06-25 10:30:00', '2026-06-25 11:30:00', 'ที่จอดรถไม่เพียงพอสำหรับเจ้าหน้าที่และผู้มาติดต่อ 200 คันต่อวัน ทำให้จอดรถซ้อนคันและกีดขวางทางเข้าออก', 'ปรับปรุงพื้นที่ว่างเปล่าเป็นลานจอดรถชั่วคราวเพิ่ม 50 คัน และจัดระบบจราจรในหน่วยงาน', 'เสนอของบประมาณสร้างอาคารจอดรถ 3 ชั้น และส่งเสริมการใช้รถร่วมกัน (Car Pool)', 'อยู่ระหว่างดำเนินการ', '0', NULL, '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('25', '4', 'R10004', 'กลุ่มขับเคลื่อนยุทธศาสตร์และพัฒนากำลังคน', NULL, 'ความเสี่ยงด้านสิ่งแวดล้อม', NULL, 'D', NULL, '2026-07-05 07:00:00', '2026-07-05 08:00:00', 'หม้อแปลงไฟฟ้าภายในหน่วยงานระเบิดเสียงดัง ทำให้ไฟฟ้าดับทั้งอาคาร 8 ชั่วโมง อุปกรณ์การแพทย์เสียหาย', 'ประสานการไฟฟ้าส่วนภูมิภาคซ่อมแซมเร่งด่วน ใช้เครื่องสำรองไฟ (UPS) สำหรับอุปกรณ์ที่จำเป็น', 'ติดตั้งเครื่องสำรองไฟอัตโนมัติ (Generator) สำหรับทั้งอาคาร และบำรุงรักษาหม้อแปลงไฟฟ้าทุกปี', 'ดำเนินการแล้ว', '1', '2026-07-06 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('26', '5', 'R10005', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยสูงอายุ', NULL, 'ปัญหาและข้อเสนอแนะที่อยากให้ช่วยแก้ไข', NULL, 'F', NULL, '2026-07-07 07:30:00', '2026-07-07 08:30:00', 'ระบบนัดหมายออนไลน์สำหรับผู้สูงอายุใช้งานยาก เนื่องจาก UI/UX ไม่เป็นมิตรกับผู้สูงอายุ ทำให้ผู้สูงอายุ 60% ไม่สามารถใช้งานได้', 'เปิดช่องทางนัดหมายทางโทรศัพท์เพิ่ม 2 คู่สาย และมีเจ้าหน้าที่ช่วยเหลือการนัดหมายหน้างาน', 'พัฒนา Mobile App ที่มีฟังก์ชั่นตัวอักษรใหญ่และเสียงอ่านภาษาไทย พร้อมอบรม อสม. สอนใช้แอพ', 'ดำเนินการแล้ว', '1', '2026-07-07 14:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('27', '1', 'R10001', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยสูงอายุ', NULL, 'ปัญหาและข้อเสนอแนะที่อยากให้ช่วยแก้ไข', NULL, 'D', NULL, '2026-06-30 14:00:00', '2026-06-30 15:00:00', 'ระบบส่งต่อผู้ป่วยระหว่าง รพ.สต. กับโรงพยาบาลแม่ข่ายไม่มีประสิทธิภาพ ข้อมูลสูญหายระหว่างทาง 20%', 'ใช้ระบบ LINE Official ในการสื่อสารข้อมูลเบื้องต้นระหว่างหน่วยบริการ และส่งเอกสารตามไปภายหลัง', 'พัฒนา Health Information Exchange (HIE) ที่เชื่อมโยงข้อมูลระหว่างหน่วยบริการทุกระดับ', 'ดำเนินการแล้ว', '1', '2026-07-01 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('28', '4', 'R10004', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยเรียน', NULL, 'ปัญหาและข้อเสนอแนะที่อยากให้ช่วยแก้ไข', NULL, 'C', NULL, '2026-06-20 09:00:00', '2026-06-20 10:00:00', 'เครื่องวัดความดันโลหิตอัตโนมัติให้ค่าที่คลาดเคลื่อนเกิน ±10 mmHg เมื่อเทียบกับเครื่องวัดแบบปรอท', 'ปรับเทียบ (Calibrate) เครื่องวัดใหม่ทั้งหมด 15 เครื่อง และทดสอบความแม่นยำกับค่ามาตรฐาน', 'จัดทำแผนสอบเทียบเครื่องมือแพทย์ทุก 6 เดือน และเปลี่ยนเครื่องที่อายุเกิน 5 ปี', 'ดำเนินการแล้ว', '1', '2026-06-21 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('29', '6', 'R10006', 'กลุ่มพัฒนาอนามัยและสิ่งแวดล้อม', NULL, 'ปัญหาและข้อเสนอแนะที่อยากให้ช่วยแก้ไข', NULL, 'B', NULL, '2026-07-01 11:00:00', '2026-07-01 12:00:00', 'ถังขยะติดเชื้อในชุมชนไม่มีการแยกประเภทอย่างถูกต้อง ประชาชนทิ้งขยะอันตรายปะปนกับขยะทั่วไป', 'จัดอบรม อสม. และผู้นำชุมชนเรื่องการคัดแยกขยะติดเชื้อ และจัดหาถังขยะติดเชื้อให้ชุมชน 50 ใบ', 'รณรงค์ให้ความรู้ผ่านหอกระจายข่าวทุกสัปดาห์ และตั้งจุดรวบรวมขยะอันตรายในชุมชนทุก 1 กม.', 'ดำเนินการแล้ว', '1', '2026-07-02 08:00:00', '2026-07-11 11:15:48', '2026-07-11 11:15:48'),
('30', '3', 'R10003', 'กลุ่มพัฒนาการส่งเสริมสุขภาพวัยทำงาน', NULL, 'ปัญหาและข้อเสนอแนะที่อยากให้ช่วยแก้ไข', NULL, 'A', NULL, '2026-07-10 15:00:00', '2026-07-10 16:00:00', 'โปรแกรมคำนวณดัชนีมวลกาย (BMI) ในระบบรายงานสุขภาพไม่รองรับหน่วยวัดแบบไทย (ซม./กก.)', 'ปรับสูตรคำนวณในโปรแกรมให้รองรับหน่วยวัดมาตรฐานไทย และทดสอบความถูกต้องของผลลัพธ์', 'พัฒนาโปรแกรมให้รองรับหลายหน่วยวัดและมีฟังก์ชั่นแปลงหน่วยอัตโนมัติ', 'กำลังดำเนินการ', '0', NULL, '2026-07-11 11:15:48', '2026-07-11 11:15:48');

